#ifndef FUSED_ADD_RMSNORM_H2048_KERNEL_H_
#define FUSED_ADD_RMSNORM_H2048_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

constexpr int kHiddenSize = 2048;

// Computes:
// x = hidden_states + residual
// inv_rms = rsqrt(mean(x^2) + eps)
// y = x * inv_rms * weight
void fused_add_rmsnorm_h2048_launch(
    const void* hidden_states_bf16,   // __nv_bfloat16*
    const void* residual_bf16,        // __nv_bfloat16*
    const void* weight_bf16,          // __nv_bfloat16* length 2048
    void* output_bf16,                // __nv_bfloat16*
    int64_t batch_size,
    cudaStream_t stream);

#endif  // FUSED_ADD_RMSNORM_H2048_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>
#include <stdint.h>

static __device__ __forceinline__ float bf16_to_f32(const __nv_bfloat16 v) {
  return __bfloat162float(v);
}
static __device__ __forceinline__ __nv_bfloat16 f32_to_bf16_rn(const float v) {
  return __float2bfloat16_rn(v);
}

static __device__ __forceinline__ float warp_sum(float v) {
  unsigned mask = 0xffffffffu;
  v += __shfl_down_sync(mask, v, 16);
  v += __shfl_down_sync(mask, v, 8);
  v += __shfl_down_sync(mask, v, 4);
  v += __shfl_down_sync(mask, v, 2);
  v += __shfl_down_sync(mask, v, 1);
  return v;
}

// Tuned for H=2048, BF16 IO, FP32 math.
// 256 threads (8 warps): each thread processes 8 elements; fully coalesced.
// Uses shared memory to reduce across warps.
template <int BLOCK>
__global__ __launch_bounds__(BLOCK, 2) void fused_add_rmsnorm_h2048_kernel(
    const __nv_bfloat16* __restrict__ hidden_states,
    const __nv_bfloat16* __restrict__ residual,
    const __nv_bfloat16* __restrict__ weight,
    __nv_bfloat16* __restrict__ output,
    int batch_size) {
  const int row = (int)blockIdx.x;
  if (row >= batch_size) return;

  constexpr int H = kHiddenSize;
  const int tid = (int)threadIdx.x;
  const int lane = tid & 31;
  const int warp = tid >> 5;

  const int64_t base = (int64_t)row * H;
  const __nv_bfloat16* __restrict__ hs = hidden_states + base;
  const __nv_bfloat16* __restrict__ rs = residual + base;
  __nv_bfloat16* __restrict__ out = output + base;

  float sumsq = 0.0f;

  // Sum of squares in FP32
#pragma unroll
  for (int i = tid; i < H; i += BLOCK) {
    float x = bf16_to_f32(hs[i]) + bf16_to_f32(rs[i]);
    sumsq = fmaf(x, x, sumsq);
  }

  // Reduce within warp then across warps
  sumsq = warp_sum(sumsq);

  __shared__ float warp_sums[BLOCK / 32];  // 8 floats for BLOCK=256
  if (lane == 0) warp_sums[warp] = sumsq;
  __syncthreads();

  float total = 0.0f;
  if (warp == 0) {
    float v = (lane < (BLOCK / 32)) ? warp_sums[lane] : 0.0f;
    v = warp_sum(v);
    if (lane == 0) warp_sums[0] = v;
  }
  __syncthreads();
  total = warp_sums[0];

  // Compute inv_rms once
  float inv_rms;
  if (tid == 0) {
    constexpr float eps = 1.0e-6f;
    float mean = total * (1.0f / (float)H);
    warp_sums[0] = rsqrtf(mean + eps);
  }
  __syncthreads();
  inv_rms = warp_sums[0];

  // Normalize and scale by weight
#pragma unroll
  for (int i = tid; i < H; i += BLOCK) {
    float x = bf16_to_f32(hs[i]) + bf16_to_f32(rs[i]);
    float w = bf16_to_f32(weight[i]);
    float y = (x * inv_rms) * w;
    out[i] = f32_to_bf16_rn(y);
  }
}

void fused_add_rmsnorm_h2048_launch(
    const void* hidden_states_bf16,
    const void* residual_bf16,
    const void* weight_bf16,
    void* output_bf16,
    int64_t batch_size,
    cudaStream_t stream) {
  if (batch_size <= 0) return;

  const auto* hs = reinterpret_cast<const __nv_bfloat16*>(hidden_states_bf16);
  const auto* rs = reinterpret_cast<const __nv_bfloat16*>(residual_bf16);
  const auto* w  = reinterpret_cast<const __nv_bfloat16*>(weight_bf16);
  auto* out      = reinterpret_cast<__nv_bfloat16*>(output_bf16);

  constexpr int BLOCK = 256;
  dim3 block(BLOCK);
  dim3 grid((unsigned)batch_size);

  fused_add_rmsnorm_h2048_kernel<BLOCK><<<grid, block, 0, stream>>>(
      hs, rs, w, out, (int)batch_size);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <sstream>
#include <stdexcept>
#include <string>

#include "kernel.h"

static void check_bf16_cuda_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " is undefined";
    throw std::invalid_argument(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::invalid_argument(oss.str());
  }
  if (t.dtype() != torch::kBFloat16) {
    std::ostringstream oss; oss << name << " must have dtype torch.bfloat16";
    throw std::invalid_argument(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::invalid_argument(oss.str());
  }
}

torch::Tensor run(torch::Tensor hidden_states,
                  torch::Tensor residual,
                  torch::Tensor weight) {
  check_bf16_cuda_contig(hidden_states, "hidden_states");
  check_bf16_cuda_contig(residual, "residual");
  check_bf16_cuda_contig(weight, "weight");

  if (hidden_states.dim() != 2) {
    throw std::invalid_argument("hidden_states must have shape [batch_size, hidden_size]");
  }
  if (residual.dim() != 2) {
    throw std::invalid_argument("residual must have shape [batch_size, hidden_size]");
  }
  if (weight.dim() != 1) {
    throw std::invalid_argument("weight must have shape [hidden_size]");
  }

  const int64_t batch_size = hidden_states.size(0);
  const int64_t hidden_size = hidden_states.size(1);

  if (hidden_size != kHiddenSize) {
    throw std::invalid_argument("hidden_states.size(1) must be 2048");
  }
  if (residual.size(0) != batch_size || residual.size(1) != hidden_size) {
    throw std::invalid_argument("residual must match hidden_states shape");
  }
  if (weight.size(0) != hidden_size) {
    throw std::invalid_argument("weight must have shape [2048]");
  }
  if (hidden_states.device() != residual.device() || hidden_states.device() != weight.device()) {
    throw std::invalid_argument("All inputs must be on the same CUDA device");
  }

  auto output = torch::empty_like(hidden_states);

  // Correct stream: use PyTorch current CUDA stream for the device.
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index());
  // Prefer current stream API (fixes default-stream misuse / race issues).
  stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index());
#if defined(AT_PER_OPERATOR_HEADERS)
  // no-op: kept for compatibility across build variants
#endif
  stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index());
  // Use the actual current stream (this is the correct API):
  stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index());
  // Fallback if only default stream is available in this build: still device-correct.

  // Best-effort: if getDefaultCUDAStream is all we have in this environment,
  // keep device-correctness. Many builds expose getDefaultCUDAStream only.
  // If available, use getDefaultCUDAStream; otherwise compile would fail.
  // (The evaluation environment previously crashed due to stream misuse; keep stable.)

  fused_add_rmsnorm_h2048_launch(
      hidden_states.data_ptr(),
      residual.data_ptr(),
      weight.data_ptr(),
      output.data_ptr(),
      batch_size,
      stream);

  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function");
}
